// Generated by Claude Opus 4.6

import userEvent from '@testing-library/user-event';
import React from 'react';

import { ConfirmationModal } from '@/pages/RestoreFromBackup/ConfirmationModal';
import getComponentRenderer, { screen } from '@/services/__mocks__/getComponentRenderer';

const mockOnConfirm = jest.fn();
const mockOnCancel = jest.fn();

const { renderComponent } = getComponentRenderer(getComponent);

describe('ConfirmationModal', () => {
  afterEach(() => {
    jest.clearAllMocks();
  });

  test('should render when open', () => {
    renderComponent();

    expect(screen.getByText('Confirm Restore from Backup')).toBeInTheDocument();
    expect(
      screen.getByText('The following workspace will be created and restored from backup:'),
    ).toBeInTheDocument();
  });

  test('should not render when closed', () => {
    renderComponent({ isOpen: false });

    expect(screen.queryByText('Confirm Restore from Backup')).not.toBeInTheDocument();
  });

  test('should display workspace name', () => {
    renderComponent();

    expect(screen.getByTestId('confirm-workspace-name')).toHaveTextContent('my-workspace');
  });

  test('should display restore mode for same-cluster', () => {
    renderComponent();

    expect(screen.getByTestId('confirm-restore-mode')).toHaveTextContent('Same cluster');
  });

  test('should display restore mode for cross-cluster', () => {
    renderComponent({ restoreMode: 'cross-cluster' });

    expect(screen.getByTestId('confirm-restore-mode')).toHaveTextContent('Cross cluster');
  });

  test('should display image URL', () => {
    renderComponent();

    expect(screen.getByTestId('confirm-image-url')).toHaveTextContent(
      'image-registry.openshift-image-registry.svc:5000/user-namespace/my-workspace:latest',
    );
  });

  test('should call onConfirm when confirm button is clicked', async () => {
    renderComponent();

    const confirmButton = screen.getByTestId('restore-confirm-button');
    await userEvent.click(confirmButton);

    expect(mockOnConfirm).toHaveBeenCalled();
  });

  test('should call onCancel when cancel button is clicked', async () => {
    renderComponent();

    const cancelButton = screen.getByTestId('restore-confirm-cancel-button');
    await userEvent.click(cancelButton);

    expect(mockOnCancel).toHaveBeenCalled();
  });

  // Note: Snapshot test omitted because PatternFly Modal uses React portals,
  // which are incompatible with react-test-renderer.
});

function getComponent(
  options: {
    isOpen?: boolean;
    restoreMode?: 'same-cluster' | 'cross-cluster';
  } = {},
) {
  return (
    <ConfirmationModal
      isOpen={options.isOpen !== false}
      restoreMode={options.restoreMode || 'same-cluster'}
      workspaceName="my-workspace"
      imageUrl="image-registry.openshift-image-registry.svc:5000/user-namespace/my-workspace:latest"
      onConfirm={mockOnConfirm}
      onCancel={mockOnCancel}
    />
  );
}
